import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../styles/Home.css';

function Home() {
  const [activeTab, setActiveTab] = useState('home');
  const [jobs, setJobs] = useState([]);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    fetchJobs();
  }, []);

  const fetchJobs = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/jobs');
      if (response.data.success) {
        setJobs(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching jobs:', error);
    }
  };

  const goHome = () => {
    setActiveTab('home');
    setMessage({ type: '', text: '' });
  };

  return (
    <div className="home-container">
      {activeTab === 'home' && (
        <>
          {/* Hero Section */}
          <section className="hero-section">
            <h2>Find Your Dream Job Today</h2>
            <p>Connect with top employers and find opportunities that match your skills.</p>

            <div className="hero-search">
              <input type="text" className="search-input" placeholder="Skills, Designation, Companies" />
              <input type="text" className="search-input" placeholder="Location" />
              <button className="search-btn">Search</button>
            </div>
          </section>

          {/* Action Grid */}
          <section className="action-grid">
            <div className="action-card" onClick={() => setActiveTab('post-job')}>
              <h3> Post a New Job</h3>
              <p>Recruit the best talent with our AI-powered shortlisting.</p>
            </div>
            <div className="action-card" onClick={() => setActiveTab('upload-resume')}>
              <h3> Upload Resume</h3>
              <p>Submit your resume for multiple job openings instantly.</p>
            </div>
            <div className="action-card" onClick={() => setActiveTab('dashboard')}>
              <h3> Admin Dashboard</h3>
              <p>View rankings, manage jobs, and analyze candidates.</p>
            </div>
          </section>

          {/* Job Feed */}
          <section className="jobs-section">
            <h3 className="section-title">Latest Job Openings</h3>
            <div className="jobs-grid">
              {jobs.length > 0 ? (
                jobs.map(job => (
                  <div key={job._id} className="job-card">
                    <div className="job-header">
                      <div>
                        <h4 className="job-title">{job.title}</h4>
                        <div className="company-name">{job.company || 'Unknown Company'}</div>
                      </div>
                    </div>
                    <div className="job-tags">
                      {job.location && <span className="tag"> {job.location}</span>}
                      {job.type && <span className="tag"> {job.type}</span>}
                    </div>
                    <p className="job-description">{job.description}</p>
                    <button className="apply-btn" onClick={() => setActiveTab('upload-resume')}>Apply Now</button>
                  </div>
                ))
              ) : (
                <p style={{ gridColumn: '1/-1', textAlign: 'center', color: '#666' }}>
                  No active job openings found. Be the first to post one!
                </p>
              )}
            </div>
          </section>
        </>
      )}

      {/* Forms & Dashboard Views */}
      {activeTab !== 'home' && (
        <div style={{ maxWidth: '800px', margin: '0 auto' }}>
          <button onClick={goHome} style={{ marginBottom: '20px', background: 'none', color: '#666', fontSize: '1rem', display: 'flex', alignItems: 'center', gap: '5px' }}>
             Back to Home
          </button>

          {activeTab === 'post-job' && (
            <div className="form-container">
              <h2>Post a New Job</h2>
              <JobPostForm onJobCreated={() => { fetchJobs(); goHome(); }} setMessage={setMessage} />
            </div>
          )}

          {activeTab === 'upload-resume' && (
            <div className="form-container">
              <h2>Upload Your Resume</h2>
              <ResumeUploadForm jobs={jobs} setMessage={setMessage} />
            </div>
          )}

          {activeTab === 'dashboard' && (
             <div className="form-container">
               <h2>Ranking Dashboard</h2>
               <Dashboard jobs={jobs} />
             </div>
          )}
        </div>
      )}

      {message.text && (
        <div className={`message ${message.type}`} style={{ position: 'fixed', bottom: '20px', right: '20px', zIndex: 1000, boxShadow: '0 4px 12px rgba(0,0,0,0.15)' }}>
          {message.text}
        </div>
      )}
    </div>
  );
}

function JobPostForm({ onJobCreated, setMessage }) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    requiredSkills: '',
    company: '',
    location: ''
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const skills = formData.requiredSkills.split(',').map(s => s.trim()).filter(s => s);
      const response = await axios.post('http://localhost:5000/api/jobs', {
        ...formData,
        requiredSkills: skills
      });

      if (response.data.success) {
        setMessage({ type: 'success', text: 'Job posted successfully!' });
        setFormData({ title: '', description: '', requiredSkills: '', company: '', location: '' });
        onJobCreated();
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Error posting job' });
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div className="form-group">
        <label>Job Title</label>
        <input
          type="text"
          value={formData.title}
          onChange={(e) => setFormData({...formData, title: e.target.value})}
          required
          placeholder="e.g. Senior Software Engineer"
        />
      </div>
      <div className="form-group">
        <label>Company Name</label>
        <input
          type="text"
          value={formData.company}
          onChange={(e) => setFormData({...formData, company: e.target.value})}
          placeholder="e.g. TechCorp Inc."
        />
      </div>
      <div className="form-group">
        <label>Location</label>
        <input
          type="text"
          value={formData.location}
          onChange={(e) => setFormData({...formData, location: e.target.value})}
          placeholder="e.g. Remote, New York"
        />
      </div>
      <div className="form-group">
        <label>Job Description</label>
        <textarea
          value={formData.description}
          onChange={(e) => setFormData({...formData, description: e.target.value})}
          required
          rows="5"
          placeholder="Describe the role and responsibilities..."
        />
      </div>
      <div className="form-group">
        <label>Required Skills (comma-separated)</label>
        <input
          type="text"
          value={formData.requiredSkills}
          onChange={(e) => setFormData({...formData, requiredSkills: e.target.value})}
          placeholder="e.g. React, Node.js, Python"
        />
      </div>
      <button type="submit" className="primary-btn">Post Job</button>
    </form>
  );
}

function ResumeUploadForm({ jobs, setMessage }) {
  const [formData, setFormData] = useState({
    candidateName: '',
    email: '',
    phone: '',
    jobId: ''
  });
  const [file, setFile] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setMessage({ type: 'error', text: 'Please select a resume file' });
      return;
    }

    const uploadData = new FormData();
    uploadData.append('resume', file);
    Object.keys(formData).forEach(key => uploadData.append(key, formData[key]));

    try {
      const response = await axios.post('http://localhost:5000/api/resumes/upload', uploadData);
      if (response.data.success) {
        setMessage({ type: 'success', text: 'Resume uploaded successfully!' });
        setFormData({ candidateName: '', email: '', phone: '', jobId: '' });
        setFile(null);
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Error uploading resume' });
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div className="form-group">
        <label>Job to Apply For</label>
        <select
          value={formData.jobId}
          onChange={(e) => setFormData({...formData, jobId: e.target.value})}
          required
        >
          <option value="">-- Select a Job --</option>
          {jobs.map(job => (
            <option key={job._id} value={job._id}>
              {job.title} - {job.company || 'Company'}
            </option>
          ))}
        </select>
      </div>
      <div className="form-group">
        <label>Full Name</label>
        <input
          type="text"
          value={formData.candidateName}
          onChange={(e) => setFormData({...formData, candidateName: e.target.value})}
          required
          placeholder="John Doe"
        />
      </div>
      <div className="form-group">
        <label>Email Address</label>
        <input
          type="email"
          value={formData.email}
          onChange={(e) => setFormData({...formData, email: e.target.value})}
          required
          placeholder="john@example.com"
        />
      </div>
      <div className="form-group">
        <label>Phone Number</label>
        <input
          type="tel"
          value={formData.phone}
          onChange={(e) => setFormData({...formData, phone: e.target.value})}
          placeholder="+1 (555) 000-0000"
        />
      </div>
      <div className="form-group">
        <label>Resume (PDF/DOCX)</label>
        <input
          type="file"
          accept=".pdf,.docx"
          onChange={(e) => setFile(e.target.files[0])}
          required
          style={{ padding: '5px' }}
        />
      </div>
      <button type="submit" className="primary-btn">Submit Application</button>
    </form>
  );
}

function Dashboard({ jobs }) {
  const [selectedJobId, setSelectedJobId] = useState('');
  const [rankings, setRankings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const generateRankings = async () => {
    if (!selectedJobId) return;
    setLoading(true);
    setError('');
    try {
      const response = await axios.post(`http://localhost:5000/api/rankings/generate/${selectedJobId}`);
      if (response.data.success) {
        await fetchRankings();
      } else {
        setError(response.data.message || 'Failed to generate rankings');
      }
    } catch (error) {
      const errorMsg = error.response?.data?.message || error.message || 'Failed to generate rankings';
      setError(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  const fetchRankings = async () => {
    if (!selectedJobId) return;
    try {
      const response = await axios.get(`http://localhost:5000/api/rankings/job/${selectedJobId}`);
      if (response.data.success) {
        setRankings(response.data.data);
        setError('');
      }
    } catch (error) {
      setError('Failed to fetch rankings');
    }
  };

  useEffect(() => {
    if (selectedJobId) {
      fetchRankings();
    } else {
      setRankings([]);
      setError('');
    }
  }, [selectedJobId]);

  return (
    <div className="dashboard">
      <div className="form-group">
        <label>Select Job to Evaluate</label>
        <div style={{ display: 'flex', gap: '10px' }}>
          <select 
            value={selectedJobId} 
            onChange={(e) => setSelectedJobId(e.target.value)}
            style={{ flex: 1 }}
          >
            <option value="">-- Select a Job --</option>
            {jobs.map(job => (
              <option key={job._id} value={job._id}>{job.title}</option>
            ))}
          </select>
          <button 
            onClick={generateRankings} 
            disabled={!selectedJobId || loading}
            className="primary-btn"
            style={{ width: 'auto' }}
          >
            {loading ? 'Generating...' : 'Generate Rankings'}
          </button>
        </div>
      </div>

      {error && (
        <div className="message error">
           {error}
        </div>
      )}

      {loading && <div style={{textAlign: 'center', padding: '2rem'}}> Processing resumes and calculating scores...</div>}

      {!loading && rankings.length === 0 && selectedJobId && !error && (
        <div style={{textAlign: 'center', padding: '3rem', color: '#666', border: '2px dashed #ccc', borderRadius: '8px'}}>
          No rankings yet. Click <strong>Generate Rankings</strong> to screen candidates.
        </div>
      )}

      {rankings.length > 0 && (
        <div className="rankings-list" style={{ marginTop: '30px' }}>
          <h3 style={{ borderBottom: '1px solid #eee', paddingBottom: '10px' }}>Top Candidates ({rankings.length})</h3>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            {rankings.map((ranking) => (
              <div key={ranking._id} style={{ 
                display: 'flex', 
                alignItems: 'center', 
                padding: '15px', 
                background: '#fff', 
                border: '1px solid #eee', 
                borderRadius: '8px',
                gap: '15px'
              }}>
                <div style={{ 
                  background: ranking.matchPercentage > 70 ? '#e6f4ea' : (ranking.matchPercentage > 50 ? '#fff8e1' : '#fce8e6'), 
                  color: ranking.matchPercentage > 70 ? '#0f8546' : (ranking.matchPercentage > 50 ? '#f9a825' : '#d93025'),
                  fontWeight: 'bold', 
                  fontSize: '1.2rem',
                  padding: '10px',
                  borderRadius: '50%',
                  width: '50px',
                  height: '50px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center'
                }}>
                  {ranking.matchPercentage?.toFixed(0)}%
                </div>

                <div style={{ flex: 1 }}>
                  <h4 style={{ margin: '0 0 5px 0' }}>{ranking.resumeId?.candidateName || 'Unknown Candidate'}</h4>
                  <p style={{ margin: 0, color: '#666', fontSize: '0.9rem' }}>{ranking.resumeId?.email}</p>
                </div>

                <div style={{ width: '200px' }}>
                  <div style={{ fontSize: '0.85rem', color: '#666' }}>Matched Skills:</div>
                  <div style={{ fontSize: '0.9rem', color: '#2557a7' }}>
                    {ranking.matchedSkills?.slice(0, 3).join(', ')} 
                    {ranking.matchedSkills?.length > 3 && ` +${ranking.matchedSkills.length - 3} more`}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export default Home;
